public async renderError(
  err: Error | null,
  req: ServerRequest,
  res: ServerResponse,
  pathname: string,
  query: NextParsedUrlQuery = {},
  setHeaders = true
): Promise<void> {
  return getTracer().trace(BaseServerSpan.renderError, async () => {
    return this.renderErrorImpl(err, req, res, pathname, query, setHeaders)
  })
