private async renderErrorImpl(
  err: Error | null,
  req: ServerRequest,
  res: ServerResponse,
  pathname: string,
  query: NextParsedUrlQuery = {},
  setHeaders = true
): Promise<void> {
  if (setHeaders) {
    res.setHeader(
      'Cache-Control',
      'private, no-cache, no-store, max-age=0, must-revalidate'

    relative(process.cwd(), this.dir)
  )
  addRequestMeta(req.originalRequest, 'distDir', this.distDir)
  await module.handler(req.originalRequest, res.originalResponse, {
    waitUntil: this.getWaitUntil(),
  })
  return true
}

protected async renderHTML(
  req: NodeNextRequest,
  res: NodeNextResponse,
  pathname: string,
  query: NextParsedUrlQuery,
  renderOpts: LoadedRenderOpts
): Promise<RenderResult> {
  return getTracer().trace(NextNodeServerSpan.renderHTML, async () =>
    this.renderHTMLImpl(req, res, pathname, query, renderOpts)
  )
}

private async renderHTMLImpl(
  req: NodeNextRequest,
  res: NodeNextResponse,
  pathname: string,
  query: NextParsedUrlQuery,
  renderOpts: LoadedRenderOpts
): Promise<RenderResult> {
  if (process.env.NEXT_MINIMAL) {
    throw new Error(
      'Invariant: renderHTML should not be called in minimal mode'
    )
    // the `else` branch is needed for tree-shaking
  } else {
    // Due to the way we pass data by mutating `renderOpts`, we can't extend the
    // object here but only updating its `nextFontManifest` field.
    // https://github.com/vercel/next.js/blob/df7cbd904c3bd85f399d1ce90680c0ecf92d2752/packages/next/server/render.tsx#L947-L952
    renderOpts.nextFontManifest = this.nextFontManifest

    if (this.enabledDirectories.app && renderOpts.isAppPath) {
      return lazyRenderAppPage(
        req,
        res,
        pathname,
        query,
        // This code path does not service revalidations for unknown param
        // shells. As a result, we don't need to pass in the unknown params.
        null,
        renderOpts as LoadedRenderOpts<AppPageModule>,
        this.getServerComponentsHmrCache(),
        {
          buildId: this.buildId,
          deploymentId: this.deploymentId,
          clientAssetToken: this.nextConfig.experimental
            .supportsImmutableAssets
            ? ''
            : this.deploymentId,
        }
      )
    } else {
      // TODO: re-enable this once we've refactored to use implicit matches
      // throw new Error('Invariant: render should have used routeModule')

      return lazyRenderPagesPage(
        req.originalRequest,
        res.originalResponse,
        pathname,
        query,
        renderOpts as LoadedRenderOpts<PagesModule>,
        {
          buildId: this.buildId,
          deploymentId: this.deploymentId,
          clientAssetToken: this.nextConfig.experimental
            .supportsImmutableAssets
            ? undefined
            : this.deploymentId,
          customServer: this.serverOptions.customServer || undefined,
        },
        {
          isFallback: false,
          isDraftMode: renderOpts.isDraftMode,
          developmentNotFoundSourcePage: getRequestMeta(
            req,
            'developmentNotFoundSourcePage'
          ),
        }
      )
    }
  }
}

protected async imageOptimizer(
  req: NodeNextRequest,
  res: NodeNextResponse,
  paramsResult: import('./image-optimizer').ImageParamsResult,
  previousCacheEntry?: IncrementalResponseCacheEntry | null
): Promise<{
  buffer: Buffer
  contentType: string
  maxAge: number
  upstreamEtag: string
  etag: string
}> {
  if (process.env.NEXT_MINIMAL) {
    throw new Error(
      'invariant: imageOptimizer should not be called in minimal mode'
    )
  } else {
    const { imageOptimizer, fetchExternalImage, fetchInternalImage } =
      require('./image-optimizer') as typeof import('./image-optimizer')

    const handleInternalReq = async (
      newReq: IncomingMessage,
      newRes: ServerResponse
    ) => {
      if (newReq.url === req.url) {
        throw new Error(`Invariant attempted to optimize _next/image itself`)
      }

      if (!this.routerServerHandler) {
        throw new Error(`Invariant missing routerServerHandler`)
      }

      await this.routerServerHandler(newReq, newRes)
      return
    }

    let { href } = paramsResult

    if (
      process.env.__NEXT_TEST_MODE &&
      process.env.IS_TURBOPACK_TEST &&
      !paramsResult.isAbsolute
    ) {
      // Forward the dpl query param from the original /_next/image request to the
      // internal static file request so that the static file validation in
      // resolve-routes.ts can verify it.
      const dpl =
        typeof req.url === 'string'
          ? new URL(req.url, 'http://n').searchParams.get('dpl')
          : undefined
      if (dpl) {
        href += `${href.includes('?') ? '&' : '?'}dpl=${dpl}`
      }
    }

    const imageUpstream = paramsResult.isAbsolute
      ? await fetchExternalImage(
          href,
          this.nextConfig.images.dangerouslyAllowLocalIP,
          this.nextConfig.images.maximumResponseBody,
          this.nextConfig.images.maximumRedirects
        )
      : await fetchInternalImage(
          href,
          req.originalRequest,
          res.originalResponse,
          this.nextConfig.images.maximumResponseBody,
          handleInternalReq
        )

    return imageOptimizer(imageUpstream, paramsResult, this.nextConfig, {
      isDev: this.dev,
      previousCacheEntry,
    })
  }
}

protected getPagePath(pathname: string, locales?: string[]): string {
  return getPagePath(
    pathname,
    this.distDir,
    locales,
    this.enabledDirectories.app
  )

